import { HttpClient } from "@angular/common/http";
import { Component, OnInit, ViewChild } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { IonCheckbox, IonRadioGroup, Platform } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ClientService } from "src/app/core/services/client.service";
import { EnvService } from "src/app/core/services/env.service";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { pagingService } from "src/app/core/services/paging.service";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { atobSafe } from "src/app/core/util/atobSafe";
import { ClientInfoData } from "src/app/views/Models/Client/ClientInfoData";
import { GetLoanApplicationResponse } from "src/app/views/Models/Loan/GetLoanApplication";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { Report } from "src/app/views/Models/Reports/Report";

@Component({
  selector: "app-client-report",
  templateUrl: "./client-report.page.html",
  styleUrls: ["./client-report.page.scss"],
})
export class ClientReportPage implements OnInit {
  @ViewChild("ionCheckBox") ionCheckBox: IonCheckbox;

  //region Flags
  isMobile: boolean;
  showLoader: boolean = false;
  isSearching: boolean = true;
  isReportForm: boolean = false;
  isApplicationGrid: boolean = false;
  isRiskReport: boolean = false;
  all_applic: number = 0;
  //endregion

  //region Variables
  initialSearchType: string = "1";
  selectedClient: ClientInfoData;
  selectedClientApplications: Array<
    GetLoanApplicationResponse & { isChecked: boolean }
  >;
  selectedApplication: any[] = [];
  selectedApplicationString: string;
  ApplicationPage: number = 1;
  reportsLabels: Array<{ key: number; value: string }>;
  //endregion

  //region Forms
  ReportForm: FormGroup = this.formBuilder.group({
    reportValue: ["", Validators.required],
  });
  //endregion

  constructor(
    public formBuilder: FormBuilder,
    private platform: Platform,
    private env: EnvService,
    private http: HttpClient,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    private pdfViewerService: PdfViewerService,
    private clientService: ClientService,
    private loanApplicationService: LoanApplicationsService,
    public pagingService: pagingService
  ) {
    this.isMobile = this.platform.is("mobile");
  }

  ngOnInit() {
    this.selectedClient = null;
    this.selectedClientApplications = null;
    this.isReportForm = false;
    this.isSearching = true;
    this.isApplicationGrid = false;
    this.ReportForm.reset();
    this.reportsLabels = [
      { key: 1, value: "حالة عميل" },
      { key: 2, value: "حالة عميل مجمعة" },
      { key: 3, value: "الحركة تبعاً للعميل" },
      { key: 4, value: "حالة العميل التفصيلية" },
      { key: 5, value: "ملخص القروض تبعاً للعميل" },
      { key: 6, value: "طلبات قروض ضمنها العميل" },
      { key: 7, value: "قائمة الاقساط بالقيمة الحالية" },
      { key: 8, value: "طلبات قروض العميل" },
      { key: 9, value: "الجدارة الائتمانية" },
    ];
  }

  //region Client Search
  clientSelected(event: SearchResult) {
    this.clientService
      .getClientInfoByClientKey(event.client_key)
      .then((client) => {
        this.selectedClient = client;
        this.isSearching = false;
        this.isReportForm = true;
      });
  }

  backToSearchForm() {
    this.isSearching = true;
    this.isReportForm = false;
    this.isApplicationGrid = false;
    this.selectedClient = null;
    this.selectedClientApplications = null;
    this.ReportForm.reset();
    this.isRiskReport = false;
  }
  //endregion

  //region Select Report
  async onChangeReportValue() {
    if (this.isReportForm) {
      this.showLoader = true;
      if (
        this.ReportForm.controls.reportValue.value == 8 ||
        this.ReportForm.controls.reportValue.value == 9
      ) {
        this.selectedApplication = [];
        this.selectedClientApplications = [];
        this.selectedClientApplications = await (
          await this.loanApplicationService.getApplicationByClientKey(
            Number(this.selectedClient.clientKey)
          )
        ).map((x) => ({
          ...x,
          isChecked: false,
        }));
        this.isApplicationGrid = true;
        if (this.ReportForm.controls.reportValue.value == 9) {
          this.isRiskReport = true;
          this.selectedApplication = [];
        } else {
          this.isRiskReport = false;
        }
      } else {
        this.isRiskReport = false;
        this.isApplicationGrid = false;
        this.selectedClientApplications = null;
        this.selectedApplication = [];
      }
      this.showLoader = false;
    }
  }
  //endregion

  //region GET Report
  private b64DecodeUnicode(str): string {
    return decodeURIComponent(
      atobSafe(str)
        .split("")
        .map(function (c) {
          return "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2);
        })
        .join("")
    );
  }
  public async getClientReport() {
    let ReportValue = this.ReportForm.controls.reportValue.value;
    if (ReportValue == "" || !!!ReportValue) {
      this.alertService.showAlertError("يجب اختيار نوع تقرير", false, "موافق");
    } else {
      let reportName: string;
      let reportParameter: Array<{ key: string; value: string }> = [
        { key: "@client_key", value: this.selectedClient.clientKey },
      ];
      switch (ReportValue) {
        case 1:
          reportName = "web_02_viewclient";
          break;
        case 2:
          reportName = "web_02_viewclient_sum";
          break;
        case 3:
          reportName = "web_client_transaction_rep";
          reportParameter = [
            { key: "@cur_client_key", value: this.selectedClient.clientKey },
          ];
          break;
        case 4:
          reportName = "web_02_viewclient_details";
          break;
        case 5:
          reportName = "web_client_cosigner_loan";
          break;
        case 6:
          reportName = "web_loan_app_co";
          break;
        case 7:
          reportName = "web_client_loans_present_value";
          break;
        case 8:
          reportName = "web_02_client_applic";
          if (this.all_applic == 1) {
            this.selectedApplicationString = "";
          } else {
            this.selectedApplicationString = this.selectedApplication.join(",");
          }
          reportParameter = [
            { key: "@client_key", value: this.selectedClient.clientKey },
            { key: "@application_key", value: this.selectedApplicationString },
            { key: "@all_applic", value: this.all_applic.toString() },
          ];
          break;
        case 9:
          reportName = "web_client_risk";
          reportParameter = [
            {
              key: "@application_key",
              value: this.selectedApplication.toString(),
            },
          ];
          break;
      }
      let client_name = this.selectedClient.clientName;
      let token = await this.authService.getAccessToken();
      token = token.replace("-", "+").replace("_", "/");
      const claims = JSON.parse(atobSafe(token.split(".")[1]));
      let username: string = "";
      let pwd: string = "";
      try {
        username = this.b64DecodeUnicode(btoa(claims.user_name));
      } catch (err) {
        username = claims.user_name;
      }
      try {
        pwd = this.b64DecodeUnicode(btoa(claims.pwd));
      } catch (err) {
        pwd = claims.pwd;
      }
      this.showLoader = true;
      this.http
        .post<Report>(this.env.API_URL + `api/Reporting/GetReport`, {
          report_name: reportName,
          report_parameters: reportParameter,
          token: {
            username: username,
            password: pwd,
          },
        })
        .subscribe({
          next: async (data) => {
            this.showLoader = false;
            if (data.status_code == 200) {
              this.showClientReportPdf(data.report!, client_name);
            } else {
              await this.alertService.showAlertError(data.message, false);
            }
          },
          error: async (err) => {
            await this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  public async showClientReportPdf(pdfBase64: string, client_name: string) {
    if (!this.pdfViewerService.canViewPdf()) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }
    let reportlabel = this.reportsLabels.find(
      (x) => x.key == this.ReportForm.controls.reportValue.value
    ).value;
    await this.pdfViewerService.viewPdf(
      pdfBase64!,
      `تقرير ${{ reportlabel }} - ${{ client_name }}.pdf`,
      reportlabel
    );
  }
  //endregion

  //region Checbox
  set isAllSelected(value: boolean) {
    this.selectedClientApplications.forEach((app) => (app.isChecked = value));
  }
  onCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.selectedClientApplications.forEach(
      (app) => (app.isChecked = isChecked)
    );
    this.updateSelectedLoanForAll(isChecked);
  }
  updateSelectedLoanForAll(isChecked: boolean) {
    this.selectedApplication = [];
    if (isChecked) {
      this.selectedClientApplications.forEach((app) => {
        this.selectedApplication.push(app.applicationKey);
      });
      this.all_applic = 1;
    }
  }
  convertStringToDate(str: string) {
    let date = new Date(str);
    return date.toLocaleDateString();
  }
  onCheckboxChange(event: any, app_key: any, index: any) {
    const selectedApp =
      this.selectedClientApplications[
        index + this.pagingService.pageSize * (this.ApplicationPage - 1)
      ];

    selectedApp.isChecked = event.target.checked;
    this.updateSelectedApplicaiton(app_key, event.target.checked);
    this.updateMasterCheckbox();
    if (
      this.selectedClientApplications.length !== this.selectedApplication.length
    ) {
      if (this.selectedApplication.length === 0) {
        this.ionCheckBox.indeterminate = false;
      } else {
        this.ionCheckBox.indeterminate = true;
      }
      this.all_applic = 0;
    } else if (
      this.selectedClientApplications.length === this.selectedApplication.length
    ) {
      this.ionCheckBox.indeterminate = false;
      this.isAllSelected = true;
      this.all_applic = 1;
    }
  }
  updateSelectedApplicaiton(app_key: any, isChecked: boolean) {
    const index = this.selectedApplication.indexOf(app_key);
    if (isChecked && index === -1) {
      this.selectedApplication.push(app_key);
    } else if (!isChecked && index > -1) {
      this.selectedApplication.splice(index, 1);
    }
  }
  updateMasterCheckbox() {
    const allSelected = this.selectedClientApplications.every(
      (app) => app.isChecked
    );
    const someSelected = this.selectedClientApplications.some(
      (app) => app.isChecked
    );

    if (allSelected) {
      this.isAllSelected = true;
      this.ionCheckBox.checked = true;
    } else if (!someSelected) {
      this.ionCheckBox.checked = false;
      this.ionCheckBox.indeterminate = false;
      this.isAllSelected = false;
      this.all_applic = 0;
    }
  }
  changePaginationPage = (newPage: number): void => {
    this.ApplicationPage = newPage;
  };
  //endregion

  ReportApplicationRisk(app: number) {
    this.selectedApplication = [];
    this.selectedApplication.push(app);
    this.getClientReport();
  }
}
